for item in doc.items:

    if item.pr_detail:

        pr = frappe.db.get_value(
            "Purchase Receipt Item",
            item.pr_detail,
            "parent"
        )

        capitalization = frappe.db.exists(
            "Asset Capitalization",
            {"purchase_receipt": pr}
        )

        if not capitalization:
            frappe.throw(
                "Asset must be capitalized before creating Purchase Invoice."
            )

import frappe

for item in doc.items:

    if not item.serial_no:

        serial = frappe.get_doc({
            "doctype": "Serial No",
            "item_code": item.item_code,
            "company": doc.company,
            "status": "Active"
        })

        serial.insert(ignore_permissions=True)

        item.serial_no = serial.name

import frappe

if doc.stock_entry_type == "Material Issue":

    for item in doc.items:

        asset_cap = frappe.get_doc({
            "doctype": "Asset Capitalization",
            "company": doc.company,
            "posting_date": doc.posting_date,
            "items": [{
                "item_code": item.item_code,
                "qty": item.qty
            }]
        })

        asset_cap.insert(ignore_permissions=True)

        frappe.msgprint(
            f"Asset Capitalization {asset_cap.name} created for {item.item_code}"
        )
